defmodule YourAppWeb.URLFetcherController do
  use YourAppWeb, :controller

  def fetch(conn, %{"url" => url}) do
    case HTTPoison.get(url) do
      {:ok, response} ->
        conn
        |> put_status(:ok)
        |> json(%{data: Poison.decode(response.body)})
      
      {:error, %HTTPoison.Error{} = error} ->
        IO.inspect(error)
        conn
        |> put_status(:unprocessable_entity)
        |> json(%{message: "Failed to fetch the URL", errors: inspect(error)})
    end
  end
end